const typeDefs = gql`
  enum InvoiceStatus {
    DRAFT
    PENDING
    PAID
    OVERDUE
    CANCELLED
  }

  type InvoiceItem {
    description: String!
    quantity: Int!
    unitPrice: Float!
    amount: Float!
  }

  type Invoice {
    id: ID!
    invoiceNumber: String!
    clientName: String!
    clientEmail: String!
    items: [InvoiceItem!]!
    subtotal: Float!
    taxRate: Float!
    taxAmount: Float!
    totalAmount: Float!
    currency: String!
    status: InvoiceStatus!
    issueDate: String!
    dueDate: String!
    paidDate: String
    notes: String
    createdBy: String!
  }

  type Query {
    invoice(id: ID!): Invoice
    invoices(status: InvoiceStatus, limit: Int, offset: Int): InvoiceListResult!
  }

  type InvoiceListResult {
    invoices: [Invoice!]!
    totalCount: Int!
  }

  input InvoiceItemInput {
    description: String!
    quantity: Int!
    unitPrice: Float!
  }

  input CreateInvoiceInput {
    clientName: String!
    clientEmail: String!
    items: [InvoiceItemInput!]!
    taxRate: Float!
    currency: String
    dueDate: String!
    notes: String
  }

  input UpdateInvoiceStatusInput {
    id: ID!
    status: InvoiceStatus!
  }

  type Mutation {
    createInvoice(input: CreateInvoiceInput!): Invoice!
    updateInvoiceStatus(input: UpdateInvoiceStatusInput!): Invoice!
    deleteInvoice(id: ID!): Boolean!
  }
`;

const resolvers = {
  Query: {
    invoice: (parent, { id }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      const invoice = invoices.find(inv => inv.id === id);

      if (!invoice) {
        throw new Error(`Invoice with ID "${id}" not found`);
      }

      return invoice;
    },

    invoices: (parent, { status, limit = 10, offset = 0 }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      let filteredInvoices = [...invoices];

      if (status) {
        filteredInvoices = filteredInvoices.filter(inv => inv.status === status);
      }

      const totalCount = filteredInvoices.length;

      const paginatedInvoices = filteredInvoices.slice(offset, offset + limit);

      return {
        invoices: paginatedInvoices,
        totalCount
      };
    }
  },

  Mutation: {
    createInvoice: (parent, { input }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      const items = input.items.map(item => ({
        description: item.description,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        amount: parseFloat((item.quantity * item.unitPrice).toFixed(2))
      }));

      const subtotal = parseFloat(items.reduce((sum, item) => sum + item.amount, 0).toFixed(2));
      const taxAmount = parseFloat((subtotal * input.taxRate).toFixed(2));
      const totalAmount = parseFloat((subtotal + taxAmount).toFixed(2));

      const newInvoiceNumber = `INV-${String(invoices.length + 1).padStart(3, '0')}`;

      const newInvoice = {
        id: String(invoices.length + 1),
        invoiceNumber: newInvoiceNumber,
        clientName: input.clientName,
        clientEmail: input.clientEmail,
        items,
        subtotal,
        taxRate: input.taxRate,
        taxAmount,
        totalAmount,
        currency: input.currency || 'USD',
        status: 'PENDING',
        issueDate: new Date().toISOString().split('T')[0],
        dueDate: input.dueDate,
        paidDate: null,
        notes: input.notes || null,
        createdBy: context.user.id
      };

      invoices.push(newInvoice);

      return newInvoice;
    },

    updateInvoiceStatus: (parent, { input }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      const invoiceIndex = invoices.findIndex(inv => inv.id === input.id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${input.id}" not found`);
      }

      const invoice = invoices[invoiceIndex];

      const validTransitions = {
        DRAFT: ['PENDING', 'CANCELLED'],
        PENDING: ['PAID', 'OVERDUE', 'CANCELLED'],
        OVERDUE: ['PAID', 'CANCELLED'],
        PAID: [],
        CANCELLED: []
      };

      const allowedStatuses = validTransitions[invoice.status];
      if (!allowedStatuses || !allowedStatuses.includes(input.status)) {
        throw new Error(
          `Cannot transition invoice from "${invoice.status}" to "${input.status}". Allowed transitions: ${allowedStatuses.join(', ') || 'none'}`
        );
      }

      invoice.status = input.status;

      if (input.status === 'PAID') {
        invoice.paidDate = new Date().toISOString().split('T')[0];
      }

      invoices[invoiceIndex] = invoice;

      return invoice;
    },

    deleteInvoice: (parent, { id }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      const invoiceIndex = invoices.findIndex(inv => inv.id === id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${id}" not found`);
      }

      const invoice = invoices[invoiceIndex];

      if (invoice.status === 'PAID') {
        throw new Error('Cannot delete a paid invoice');
      }

      invoices.splice(invoiceIndex, 1);

      return true;
    }
  }
};

// Simulated authentication middleware (already verified user)
const authMiddleware = (req, res, next) => {
  // In a real app, the auth middleware would have already verified the token
  // and attached the user to the request. We simulate that here.
  req.user = {
    id: 'user-101',
    email: 'user@example.com',
    name: 'Authenticated User',
    role: 'admin'
  };
  next();
};

async function startServer() {
  const app = express();

  app.use(authMiddleware);

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    context: ({ req }) => {
      return {
        user: req.user
      };
    },
    formatError: (error) => {
      console.error('GraphQL Error:', error.message);
      return {
        message: error.message,
        path: error.path,
        extensions: {
          code: error.extensions?.code || 'INTERNAL_SERVER_ERROR'
        }
      };
    }
  });

  await server.start();
  server.applyMiddleware({ app, path: '/graphql' });

  const PORT = process.env.PORT || 4000;

  app.listen(PORT, () => {
    console.log(`Invoice Management GraphQL API running at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`\nExample queries:`);
    console.log(`  - Get invoice by ID: { invoice(id: "1") { id invoiceNumber clientName totalAmount status items { description amount } } }`);
    console.log(`  - List all invoices: { invoices { invoices { id invoiceNumber clientName totalAmount status } totalCount } }`);
    console.log(`  - Filter by status:  { invoices(status: PAID) { invoices { id invoiceNumber totalAmount } totalCount } }`);
  });
}

startServer().catch(err => {
  console.error('Failed to start server:', err);
  process.exit(1);
});

module.exports = { typeDefs, resolvers };